import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const h=JSON.parse('{"title":"MIDI Setup","description":"","frontmatter":{},"headers":[],"relativePath":"guides/midi.md","filePath":"guides/midi.md"}'),n={name:"guides/midi.md"};function i(d,a,s,l,c,u){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="midi-setup" tabindex="-1">MIDI Setup <a class="header-anchor" href="#midi-setup" aria-label="Permalink to &quot;MIDI Setup&quot;">​</a></h1><p>The Smart Contact Mic supports MIDI input and output via both hardware TRS jacks and USB.</p><h2 id="hardware-midi-trs" tabindex="-1">Hardware MIDI (TRS) <a class="header-anchor" href="#hardware-midi-trs" aria-label="Permalink to &quot;Hardware MIDI (TRS)&quot;">​</a></h2><p>The board uses <strong>TRS Type B</strong> MIDI jacks (the same standard as Arturia, Novation, and 1010music). You need a TRS-to-DIN adapter cable if your gear uses standard 5-pin DIN connectors.</p><h3 id="connecting-a-midi-keyboard" tabindex="-1">Connecting a MIDI Keyboard <a class="header-anchor" href="#connecting-a-midi-keyboard" aria-label="Permalink to &quot;Connecting a MIDI Keyboard&quot;">​</a></h3><ol><li>Connect your keyboard&#39;s MIDI out to the Smart Contact Mic MIDI in jack (via TRS or adapter)</li><li>In the patcher, add a <strong>MIDI In</strong> module</li><li>Connect the MIDI In <code>note</code> output to an Oscillator&#39;s <code>note</code> input</li><li>Connect the MIDI In <code>gate</code> output to an ADSR&#39;s <code>gate</code> input</li><li>Route the ADSR to a VCA controlling the oscillator&#39;s output</li><li>Upload the patch -- play your keyboard</li></ol><h2 id="usb-midi" tabindex="-1">USB MIDI <a class="header-anchor" href="#usb-midi" aria-label="Permalink to &quot;USB MIDI&quot;">​</a></h2><p>The board appears as a class-compliant USB MIDI device when connected to a computer. Your DAW or MIDI software can send notes and CCs directly over USB, with no additional hardware.</p><h3 id="usb-midi-in" tabindex="-1">USB MIDI In <a class="header-anchor" href="#usb-midi-in" aria-label="Permalink to &quot;USB MIDI In&quot;">​</a></h3><p>Add a <strong>USB MIDI In</strong> module. It works identically to hardware MIDI In but receives from the USB connection. You can use both simultaneously.</p><h3 id="usb-midi-out" tabindex="-1">USB MIDI Out <a class="header-anchor" href="#usb-midi-out" aria-label="Permalink to &quot;USB MIDI Out&quot;">​</a></h3><p>Add a <strong>USB MIDI Out</strong> module to send MIDI data from your patch back to the computer. Useful for recording sequences or controlling soft synths.</p><h2 id="midi-cc-control" tabindex="-1">MIDI CC Control <a class="header-anchor" href="#midi-cc-control" aria-label="Permalink to &quot;MIDI CC Control&quot;">​</a></h2><p>The patcher&#39;s on-screen MIDI strip sends CC messages to control parameters from your computer:</p><ul><li>Pot CCs are banked: Bank 1 = CC 20-23, Bank 2 = CC 24-27, ... Bank 6 = CC 40-43</li><li>Button CCs: CC 44-47 (all banks)</li><li>Bank select: CC 48</li></ul><p>External MIDI controllers can use the same CC map to control the hardware remotely.</p><h2 id="midi-control-module" tabindex="-1">MIDI Control Module <a class="header-anchor" href="#midi-control-module" aria-label="Permalink to &quot;MIDI Control Module&quot;">​</a></h2><p>For more flexible CC routing, add a <strong>MIDI Control</strong> module. It maps a specific CC number to a control output that you can connect to any parameter.</p>',18)])])}const m=e(n,[["render",i]]);export{h as __pageData,m as default};
